using UnityEngine;

public sealed class Coin : MonoBehaviour
{
    [SerializeField] private int points = 1;

    public void Collect()
    {
        GameManager.Instance.AddScore(points);
        Destroy(gameObject);
    }
}

using UnityEngine;

public sealed class EnemyPatrol : MonoBehaviour
{
    [SerializeField] private Vector2 direction = Vector2.right;
    [SerializeField] private float speed = 3f;
    [SerializeField] private float distance = 4f;

    private Vector2 startPosition;

    private void Awake()
    {
        startPosition = transform.position;
        direction = direction.normalized;
    }

    private void Update()
    {
        float offset = Mathf.PingPong(Time.time * speed, distance) - distance * 0.5f;
        transform.position = startPosition + direction * offset;
    }
}

using UnityEngine;
using UnityEngine.SceneManagement;

public sealed class GameManager : MonoBehaviour
{
    public static GameManager Instance { get; private set; }

    [SerializeField] private PlayerController player;

    private int totalCoins;
    private int score;
    private bool gameEnded;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            Destroy(gameObject);
            return;
        }

        Instance = this;
    }

    private void Start()
    {
        totalCoins = FindObjectsOfType<Coin>().Length;
        Debug.Log($"Coin Dash iniciado. Moedas na cena: {totalCoins}");
    }

    private void Update()
    {
        if (gameEnded && Input.GetKeyDown(KeyCode.R))
        {
            SceneManager.LoadScene(SceneManager.GetActiveScene().buildIndex);
        }
    }

    public void AddScore(int points)
    {
        if (gameEnded)
        {
            return;
        }

        score += points;
        Debug.Log($"Pontuação: {score}/{totalCoins}");

        if (score >= totalCoins)
        {
            WinGame();
        }
    }

    public void LoseGame()
    {
        if (gameEnded)
        {
            return;
        }

        gameEnded = true;
        SetPlayerEnabled(false);
        Debug.Log("Você perdeu! Aperte R para reiniciar.");
    }

    private void WinGame()
    {
        gameEnded = true;
        SetPlayerEnabled(false);
        Debug.Log("Você venceu! Aperte R para jogar novamente.");
    }

    private void SetPlayerEnabled(bool enabled)
    {
        if (player != null)
        {
            player.enabled = enabled;
        }
    }
}

using UnityEngine;

public sealed class PlayerController : MonoBehaviour
{
    [SerializeField] private float moveSpeed = 6f;

    private Rigidbody2D body;
    private Vector2 moveInput;

    private void Awake()
    {
        body = GetComponent<Rigidbody2D>();
    }

    private void Update()
    {
        moveInput = new Vector2(Input.GetAxisRaw("Horizontal"), Input.GetAxisRaw("Vertical"));
        moveInput = Vector2.ClampMagnitude(moveInput, 1f);
    }

    private void FixedUpdate()
    {
        body.velocity = moveInput * moveSpeed;
    }

    private void OnTriggerEnter2D(Collider2D other)
    {
        if (other.TryGetComponent(out Coin coin))
        {
            coin.Collect();
            return;
        }

        if (other.TryGetComponent(out EnemyPatrol _))
        {
            GameManager.Instance.LoseGame();
        }
    }
}

